const body = $input.first().json.body || {};

// Safely extract arguments and toolCallId (handling both flat and nested Vapi/Dograh formats)
let args = body;
let toolCallId = body.toolCallId || "unknown";

if (body.message && body.message.toolWithToolCallList && body.message.toolWithToolCallList.length > 0) {
    const toolCall = body.message.toolWithToolCallList[0].toolCall;
    toolCallId = toolCall.id;
    args = toolCall.function.arguments || {};
} else if (body.message && body.message.toolCallList && body.message.toolCallList.length > 0) {
    const toolCall = body.message.toolCallList[0];
    toolCallId = toolCall.id;
    args = toolCall.function ? toolCall.function.arguments : (toolCall.arguments || {});
}

// 1. Safely grab Date, Time, and Duration with fallbacks
let dateStr = args.date || args.day || "";
let timeStr = args.time || args.hour || "";
let durationMinutes = args.duration_minutes || args.duration || 30;

// 2. Prevent Crashes: If AI forgets the date, default to today
if (!dateStr) {
    const today = new Date();
    const yyyy = today.getFullYear();
    const mm = String(today.getMonth() + 1).padStart(2, '0');
    const dd = String(today.getDate()).padStart(2, '0');
    dateStr = `${yyyy}-${mm}-${dd}`;
}

// 3. Prevent Crashes: If AI forgets the time, default to 9:00 AM
if (!timeStr) {
    timeStr = '09:00';
}

// 4. Safely parse the date and time
let year, month, day, hour, minute;

try {
    // Split date (handles if AI accidentally sends a full ISO string with a 'T')
    [year, month, day] = dateStr.split('T')[0].split('-').map(Number);

    // Clean up the time string (strips letters but keeps numbers and colons)
    let cleanTime = timeStr.replace(/[^0-9:]/g, ''); 
    let timeParts = cleanTime.split(':');
    hour = Number(timeParts[0]);
    minute = timeParts[1] ? Number(timeParts[1]) : 0;

    // Auto-fix if AI sends "2 PM" instead of "14:00"
    if (timeStr.toLowerCase().includes('pm') && hour < 12) hour += 12;
    if (timeStr.toLowerCase().includes('am') && hour === 12) hour = 0;

} catch (e) {
    // Ultimate Fallback: If the AI sends absolute gibberish, use safe numbers so the node doesn't crash
    const d = new Date();
    year = d.getFullYear();
    month = d.getMonth() + 1;
    day = d.getDate();
    hour = 9;
    minute = 0;
}

// 5. Generate the final exact timestamps
const requestedStart = new Date(year, month - 1, day, hour, minute);
const requestedEnd = new Date(requestedStart.getTime() + durationMinutes * 60000);

// Business hours window for that specific day (9 AM to 5 PM)
const businessStart = new Date(year, month - 1, day, 9, 0);
const businessEnd = new Date(year, month - 1, day, 17, 0);

return [{
  json: {
    toolCallId: toolCallId,
    requestedStartISO: requestedStart.toISOString(),
    requestedEndISO: requestedEnd.toISOString(),
    businessStartISO: businessStart.toISOString(),
    businessEndISO: businessEnd.toISOString(),
    durationMinutes: durationMinutes,
    date: dateStr,
    time: timeStr
  }
}];

const items = $input.all();
// Safely handle if Google Calendar returns zero events
const events = items.length > 0 && items[0].json && Object.keys(items[0].json).length > 0 ? items.map(i => i.json) : [];

// Grab the parsed data and the crucial toolCallId from your first code node
const parsed = $('Code - Parse Requested Slot').first().json || {};
const toolCallId = parsed.toolCallId || "unknown";

const reqStart = new Date(parsed.requestedStartISO);
const reqEnd = new Date(parsed.requestedEndISO);
const bizStart = new Date(parsed.businessStartISO);
const bizEnd = new Date(parsed.businessEndISO);
const durationMs = (parsed.durationMinutes || 30) * 60000;

// Safely map out the busy times on the calendar
const busy = events
  .filter(e => e && e.start && e.end)
  .map(e => ({ 
    start: new Date(e.start.dateTime || e.start.date), 
    end: new Date(e.end.dateTime || e.end.date) 
  }))
  .sort((a, b) => a.start - b.start);

// Function to check if two time blocks overlap
function overlaps(s1, e1, s2, e2) { 
    return s1 < e2 && s2 < e1; 
}

// 1. Check if they asked for a time when you are closed
let isOutsideBusinessHours = false;
if (reqStart < bizStart || reqEnd > bizEnd) {
    isOutsideBusinessHours = true;
}

// 2. Check if the requested slot is free
const requestedIsFree = !isOutsideBusinessHours && !busy.some(b => overlaps(reqStart, reqEnd, b.start, b.end));

// Helper: Format time to 12-hour AM/PM so the AI reads it naturally (e.g., "2:15 PM")
function formatTime(d) {
    let h = d.getHours();
    let m = d.getMinutes();
    const ampm = h >= 12 ? 'PM' : 'AM';
    h = h % 12;
    h = h ? h : 12; // the hour '0' should be '12'
    m = m < 10 ? '0' + m : m;
    return `${h}:${m} ${ampm}`;
}

// 3. Find up to 2 alternative open slots just in case
const openSlots = [];
let cursor = new Date(bizStart);
const now = new Date();

// Prevent the bot from suggesting times that already passed earlier today
if (cursor < now) {
    cursor = now;
    // Round up to the next 15-minute mark
    const remainder = 15 - (cursor.getMinutes() % 15);
    cursor = new Date(cursor.getTime() + remainder * 60000);
}

while (cursor.getTime() + durationMs <= bizEnd.getTime() && openSlots.length < 2) {
  const slotEnd = new Date(cursor.getTime() + durationMs);
  const clashes = busy.some(b => overlaps(cursor, slotEnd, b.start, b.end));

  if (!clashes) {
    openSlots.push(formatTime(cursor));
    cursor = new Date(cursor.getTime() + durationMs);
  } else {
    cursor = new Date(cursor.getTime() + 15 * 60000); // Fast-forward 15 mins and check again
  }
}

// 4. Construct a highly conversational answer to feed directly to Dograh
let message = "";
if (isOutsideBusinessHours) {
    message = `I'm sorry, but ${formatTime(reqStart)} is outside our normal business hours. `;
    if (openSlots.length > 0) {
        message += `Our available openings that day are ${openSlots.join(' or ')}.`;
    } else {
        message += `We don't have any openings available that day.`;
    }
} else if (requestedIsFree) {
    message = `Yes, ${formatTime(reqStart)} on that date is completely available! Would you like me to go ahead and lock that in for you?`;
} else {
    message = `I'm sorry, but ${formatTime(reqStart)} is already booked. `;
    if (openSlots.length > 0) {
        message += `The next available times on that day are ${openSlots.join(' or ')}.`;
    } else {
        message += `We actually don't have any other openings left for that day.`;
    }
}

// 5. Return the payload matching Dograh/Vapi's requirements
return [{
  json: {
    toolCallId: toolCallId,
    available: requestedIsFree,
    date: parsed.date,
    requested_time: parsed.time,
    next_available_slots: openSlots,
    result: message // Dograh will read this exact string aloud
  }
}];

// Expected body: { "name": "John Smith", "phone": "+1555...", "date": "2026-07-11", "time": "15:30", "duration_minutes": 30 }
const body = $input.first().json.body;
const { name, phone, date, time } = body;
const durationMinutes = body.duration_minutes || 30;

const [year, month, day] = date.split('-').map(Number);
const [hour, minute] = time.split(':').map(Number);

const start = new Date(year, month - 1, day, hour, minute);
const end = new Date(start.getTime() + durationMinutes * 60000);

return [{
  json: {
    customer_name: name,
    customer_phone: phone,
    date, time,
    startISO: start.toISOString(),
    endISO: end.toISOString()
  }
}];

const parsed = $('Code - Parse Booking Request').first().json;
const created = $input.first().json;

return [{
  json: {
    success: true,
    confirmation_id: created.id,
    name: parsed.customer_name,
    date: parsed.date,
    time: parsed.time,
    message: `Appointment confirmed for ${parsed.customer_name} on ${parsed.date} at ${parsed.time}.`
  }
}];

const parsed = $('Code - Parse Booking Request').first().json;
return [{
  json: {
    success: false,
    reason: 'slot_taken',
    date: parsed.date,
    time: parsed.time,
    message: `Sorry, ${parsed.time} on ${parsed.date} just got booked. Please ask the caller for another time.`
  }
}];

const body = $input.first().json.body || {};

// Grab the query directly from the root of the body (based on your screenshot)
let query = body.query || body.info_type || body.topic || "";

// Fallback: If the name changes, just grab the first string it finds in the body
if (!query) {
    const values = Object.values(body);
    query = values.find(val => typeof val === 'string') || "";
}

query = query.toLowerCase();

const kb = {
  hours: "We're open Monday to Friday, 9 AM to 5 PM, and closed on weekends.",
  location: "We're located at 123 Main Street, Suite 4.",
  services: "We offer haircuts, coloring, and styling consultations.",
  pricing: "Pricing varies by service. I can have someone call you back with exact pricing, or you can book a consultation."
};

let answer = "I don't have that information, but I can have a team member follow up with you.";

// Match the keywords to the knowledge base
if (query.includes('hour') || query.includes('open') || query.includes('time') || query.includes('opening')) {
    answer = kb.hours;
} else if (query.includes('location') || query.includes('address') || query.includes('where') || query.includes('locate')) {
    answer = kb.location;
} else if (query.includes('service') || query.includes('offer') || query.includes('hair')) {
    answer = kb.services;
} else if (query.includes('price') || query.includes('cost') || query.includes('much')) {
    answer = kb.pricing;
}

return [{
  json: {
    // Pass back the toolCallId if Dograh provides it, otherwise default to "unknown"
    toolCallId: body.toolCallId || "unknown",
    answer: answer
  }
}];
